INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene', 'bebe pode tomar banho todo dia?', 'Higiene do bebê é importante, mas não precisa ser perfeita! Você está fazendo ótimo trabalho. Dicas práticas: - Observe o padrão e anote quando acontece - Converse com seu pediatra sobre o que você notou - Confie no seu instinto de mãe Mas atenção: se a pele ficar muito vermelha, inflamada ou tiver sinais de infecção, procure o pediatra.', 'higiene', 'higiene', 'higiene', 0, 'true');
