INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('geral', 'como limpar nariz bebe?', 'Sua preocupação mostra que você ama seu bebê. Vamos resolver isso juntas! Aqui está o que você pode fazer: - Observe o padrão e anote quando acontece - Converse com seu pediatra sobre o que você notou - Confie no seu instinto de mãe Mas atenção: se a situação piorar ou você tiver dúvidas, sempre consulte seu pediatra.', 'geral', 'geral', 'geral', 0, 'true');
